1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Policy {
8	  items: Item[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
16	const DEFAULT_BASE_PREMIUM = 60;
17	
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const LOYALTY_THRESHOLD = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	
27	function basePremiumForType(type: string): number {
28	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
29	}
30	
31	function itemSurcharges(item: Item): number {
32	  const base = basePremiumForType(item.type);
33	  let surcharge = 0;
34	  if (item.cursed) {
35	    surcharge += base * CURSE_SURCHARGE_RATE;
36	  }
37	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
38	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
39	  }
40	  return surcharge;
41	}
42	
43	function countByType(items: Item[]): Record<string, number> {
44	  const counts: Record<string, number> = {};
45	  for (const item of items) {
46	    counts[item.type] = (counts[item.type] ?? 0) + 1;
47	  }
48	  return counts;
49	}
50	
51	function itemGroupPremium(type: string, count: number): number {
52	  if (count === BLOCK_SIZE) {
53	    return BLOCK_PREMIUM;
54	  }
55	  return count * basePremiumForType(type);
56	}
57	
58	export function quote(policy: Policy) {
59	  const counts = countByType(policy.items);
60	
61	  let basePremium = 0;
62	  for (const [type, count] of Object.entries(counts)) {
63	    basePremium += itemGroupPremium(type, count);
64	  }
65	
66	  let totalItemSurcharges = 0;
67	  for (const item of policy.items) {
68	    totalItemSurcharges += itemSurcharges(item);
69	  }
70	
71	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
72	  const isLoyalCustomer = policy.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
73	  const loyaltyDiscount = isLoyalCustomer ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
74	  const followUpDiscount = policy.isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
75	  const totalPolicyDiscounts = loyaltyDiscount + followUpDiscount;
76	  const premium = Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge - totalPolicyDiscounts + PROCESSING_FEE);
77	  return { premium };
78	}
79	
80	const INSURANCE_VALUE: Record<string, number> = { sword: 1000 };
81	const DEDUCTIBLE = 100;
82	
83	export function claim(policy: Policy, incident: { damages: { type: string; amount: number }[] }) {
84	  let insuranceSum = 0;
85	  for (const item of policy.items) {
86	    insuranceSum += INSURANCE_VALUE[item.type] ?? 0;
87	  }
88	  const cap = 2 * insuranceSum;
89	
90	  let payout = 0;
91	  for (const damage of incident.damages) {
92	    payout += damage.amount - DEDUCTIBLE;
93	  }
94	
95	  const remainingCap = cap - payout;
96	  return { payout, remainingCap };
97	}
