84	const INSURANCE_VALUE: Record<string, number> = { sword: 1000 };
85	const DEDUCTIBLE = 100;
86	
87	export function claim(policy: Policy, incident: Incident) {
88	  let insuranceSum = 0;
89	  for (const item of policy.items) {
90	    insuranceSum += INSURANCE_VALUE[item.type] ?? 0;
91	  }
92	  const cap = 2 * insuranceSum;
93	
94	  let payout = 0;
95	  for (const damage of incident.damages) {
96	    payout += damage.amount - DEDUCTIBLE;
97	  }
98	
99	  const remainingCap = cap - payout;
100	  return { payout, remainingCap };
101	}
